  1	import * as React from 'react';
  2	import { useSafeK8sGet } from '@odf/core/hooks';
  3	import { useODFSystemFlagsSelector } from '@odf/core/redux';
  4	import { ODFSystemFlagsPayload } from '@odf/core/redux/actions';
  5	import { getResourceInNs as getCephClusterInNs } from '@odf/core/utils';
  6	import { StoragePoolDefinitionText } from '@odf/ocs/storage-pool/CreateStoragePool';
  7	import { CephBlockPoolModel } from '@odf/shared';
  8	import { ModalFooter, ModalTitle } from '@odf/shared/generic/ModalTitle';
  9	import { StatusBox } from '@odf/shared/generic/status-box';
 10	import { CommonModalProps, ModalBody } from '@odf/shared/modals/Modal';
 11	import { CephClusterModel, StorageClusterModel } from '@odf/shared/models';
 12	import { getName, getNamespace } from '@odf/shared/selectors';
 13	import { CephClusterKind, StorageClusterKind } from '@odf/shared/types';
 14	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 15	import { referenceForModel } from '@odf/shared/utils';
 16	import {
 17	  K8sModel,
 18	  K8sResourceCommon,
 19	  Patch,
 20	  k8sPatch,
 21	  useK8sWatchResource,
 22	} from '@openshift-console/dynamic-plugin-sdk';
 23	import * as _ from 'lodash-es';
 24	import { Modal, ModalVariant } from '@patternfly/react-core';
 25	import {
 26	  ADDITIONAL_FS_POOLS_CLUSTER_CR_PATH,
 27	  COMPRESSION_ON,
 28	  PoolProgress,
 29	  PoolType,
 30	} from '../../constants';
 31	import { StoragePoolBody, StoragePoolStatus } from '../../storage-pool/body';
 32	import {
 33	  StoragePoolActionType,
 34	  StoragePoolState,
 35	  blockPoolInitialState,
 36	  storagePoolReducer,
 37	} from '../../storage-pool/reducer';
 38	import { StoragePool } from '../../types';
 39	import { getFsPoolIndex, isDefaultPool } from '../../utils';
 40	import { StoragePoolModalFooter, FooterPrimaryActions } from './modal-footer';
 41	import './storage-pool-modal.scss';
 42	
 43	const updateFsPoolRequest = (
 44	  state: StoragePoolState,
 45	  storageCluster: StorageClusterKind
 46	) => {
 47	  const poolIndex = getFsPoolIndex(storageCluster, state.poolName);
 48	
 49	  const patches: Patch[] = [
 50	    {
 51	      op: 'replace',
 52	      path: `${ADDITIONAL_FS_POOLS_CLUSTER_CR_PATH}/${poolIndex}/replicated/size`,
 53	      value: Number(state.replicaSize),
 54	    },
 55	    {
 56	      op: 'replace',
 57	      path: `${ADDITIONAL_FS_POOLS_CLUSTER_CR_PATH}/${poolIndex}/compressionMode`,
 58	      value: state.isCompressed ? COMPRESSION_ON : 'none',
 59	    },
 60	  ];
 61	
 62	  return () =>
 63	    k8sPatch({
 64	      model: StorageClusterModel,
 65	      resource: storageCluster,
 66	      data: patches,
 67	    });
 68	};
 69	
 70	const cephClusterResource = {
 71	  kind: referenceForModel(CephClusterModel),
 72	  isList: true,
 73	};
 74	
 75	type UpdateStoragePoolModalProps = CommonModalProps<{
 76	  kindObj?: K8sModel;
 77	  resource: StoragePool;
 78	}>;
 79	
 80	const UpdateStoragePoolModal: React.FC<UpdateStoragePoolModalProps> = (
 81	  props
 82	) => {
 83	  const { t } = useCustomTranslation();
 84	  const { systemFlags, areFlagsLoaded, flagsLoadError } =
 85	    useODFSystemFlagsSelector();
 86	  const newProps = _.cloneDeep(props);
 87	  newProps.extraProps['systemFlags'] = systemFlags;
 88	
 89	  if (areFlagsLoaded && !flagsLoadError) {
 90	    return props?.extraProps?.resource?.type === PoolType.FILESYSTEM ? (
 91	      <UpdateFsPoolModal {...(newProps as UpdateFsPoolModalProps)} />
 92	    ) : (
 93	      <UpdateStoragePoolModalBase
 94	        {...(newProps as UpdateStoragePoolModalBaseProps)}
 95	      />
 96	    );
 97	  }
 98	  return (
 99	    <StatusBox
100	      loaded={areFlagsLoaded}
101	      loadError={flagsLoadError}
102	      label={t('Storage pool update form')}
103	    />
104	  );
105	};
106	
107	type UpdateFsPoolModalProps = CommonModalProps<{
108	  kindObj?: K8sModel;
109	  resource: StoragePool;
110	  systemFlags: ODFSystemFlagsPayload['systemFlags'];
111	}>;
112	
113	const UpdateFsPoolModal: React.FC<UpdateFsPoolModalProps> = (props) => {
114	  const { t } = useCustomTranslation();
115	  const {
116	    extraProps: { resource, systemFlags },
117	  } = props;
118	  const poolNamespace = getNamespace(resource);
119	  const clusterName = systemFlags[poolNamespace]?.ocsClusterName;
120	  const [storageCluster, storageClusterLoaded, storageClusterLoadError] =
121	    useSafeK8sGet<StorageClusterKind>(
122	      StorageClusterModel,
123	      clusterName,
124	      poolNamespace
125	    );
126	  const newProps = _.cloneDeep(props);
127	  newProps.extraProps['storageCluster'] = storageCluster;
128	
129	  if (storageClusterLoaded && !storageClusterLoadError) {
130	    return <UpdateStoragePoolModalBase {...newProps} />;
131	  }
132	  return (
133	    <StatusBox
134	      loaded={storageClusterLoaded}
135	      loadError={storageClusterLoadError}
136	      label={t('Storage pool update form')}
137	    />
138	  );
139	};
140	
141	type UpdateStoragePoolModalBaseProps = CommonModalProps<{
142	  kindObj?: K8sModel;
143	  resource: StoragePool;
144	  systemFlags: ODFSystemFlagsPayload['systemFlags'];
145	  storageCluster?: StorageClusterKind;
146	}>;
147	
148	const UpdateStoragePoolModalBase: React.FC<UpdateStoragePoolModalBaseProps> = (
149	  props
150	) => {
151	  const { t } = useCustomTranslation();
152	  const {
153	    extraProps: { resource, systemFlags, storageCluster },
154	    closeModal,
155	    isOpen,
156	  } = props;
157	  const poolNamespace = getNamespace(resource);
158	
159	  const [state, dispatch] = React.useReducer(
160	    storagePoolReducer,
161	    blockPoolInitialState
162	  );
163	  const [inProgress, setProgress] = React.useState(false);
164	  const [cephClusters, cephClustersLoaded, cephClustersLoadError] =
165	    useK8sWatchResource<CephClusterKind[]>(cephClusterResource);
166	
167	  // only single cluster per Namespace
168	  const cephCluster = getCephClusterInNs(
169	    cephClusters,
170	    poolNamespace
171	  ) as CephClusterKind;
172	
173	  const MODAL_TITLE = t('Edit Storage Pool');
174	
175	  const populateStoragePoolData = React.useCallback(
176	    (pool: StoragePool) => {
177	      dispatch({
178	        type: StoragePoolActionType.SET_POOL_NAME,
179	        payload:
180	          pool.type === PoolType.FILESYSTEM ? pool.shortName : getName(pool),
181	      });
182	      dispatch({
183	        type: StoragePoolActionType.SET_POOL_REPLICA_SIZE,
184	        payload: pool?.spec.replicated.size.toString(),
185	      });
186	      dispatch({
187	        type: StoragePoolActionType.SET_POOL_COMPRESSED,
188	        payload: pool?.spec.compressionMode === COMPRESSION_ON,
189	      });
190	    },
191	    [dispatch]
192	  );
193	
194	  const isExternalSC = systemFlags[poolNamespace]?.isExternalMode;
195	
196	  React.useEffect(() => {
197	    // restrict pool management for default pool and external cluster
198	    isExternalSC || isDefaultPool(resource)
199	      ? dispatch({
200	          type: StoragePoolActionType.SET_POOL_STATUS,
201	          payload: PoolProgress.NOTALLOWED,
202	        })
203	      : populateStoragePoolData(resource);
204	  }, [resource, isExternalSC, populateStoragePoolData]);
205	
206	  // Update block pool
207	  const updatePool = () => {
208	    setProgress(true);
209	    let updateRequest: () => Promise<K8sResourceCommon>;
210	    if (resource.type === PoolType.FILESYSTEM) {
211	      updateRequest = updateFsPoolRequest(state, storageCluster);
212	    } else {
213	      updateRequest = () => {
214	        const patch = [
215	          {
216	            op: 'replace',
217	            path: '/spec/replicated/size',
218	            value: Number(state.replicaSize),
219	          },
220	          {
221	            op: 'replace',
222	            path: '/spec/compressionMode',
223	            value: state.isCompressed ? COMPRESSION_ON : 'none',
224	          },
225	          {
226	            op: 'replace',
227	            path: '/spec/parameters/compression_mode',
228	            value: state.isCompressed ? COMPRESSION_ON : 'none',
229	          },
230	        ];
231	        return k8sPatch({
232	          model: CephBlockPoolModel,
233	          resource,
234	          data: patch,
235	        });
236	      };
237	    }
238	
239	    updateRequest().then(() => {
240	      setProgress(false);
241	      closeModal();
242	    });
243	  };
244	
245	  return (
246	    <Modal
247	      className="modal-content storage-pool__modal"
248	      isOpen={isOpen}
249	      header={
250	        <>
251	          <ModalTitle>{MODAL_TITLE}</ModalTitle>
252	          <StoragePoolDefinitionText className="pf-v6-u-ml-xl" />
253	        </>
254	      }
255	      variant={ModalVariant.medium}
256	      onClose={closeModal}
257	    >
258	      {cephClustersLoaded && !cephClustersLoadError ? (
259	        <>
260	          <ModalBody>
261	            {state.poolStatus ? (
262	              <div key="progress-modal">
263	                <StoragePoolStatus
264	                  status={state.poolStatus}
265	                  name={state.poolName}
266	                  error={state.errorMessage}
267	                />
268	              </div>
269	            ) : (
270	              <StoragePoolBody
271	                cephCluster={cephCluster}
272	                state={state}
273	                dispatch={dispatch}
274	                showPoolStatus
275	                poolType={resource.type}
276	                disablePoolType
277	                isUpdate
278	                prefixName={PoolType.FILESYSTEM && resource.fsName}
279	              />
280	            )}
281	          </ModalBody>
282	          <ModalFooter inProgress={inProgress}>
283	            <StoragePoolModalFooter
284	              state={state}
285	              dispatch={dispatch}
286	              onSubmit={updatePool}
287	              cancel={closeModal}
288	              close={closeModal}
289	              primaryAction={FooterPrimaryActions(t).UPDATE}
290	            />
291	          </ModalFooter>
292	        </>
293	      ) : (
294	        <StatusBox
295	          loadError={cephClustersLoadError}
296	          loaded={cephClustersLoaded}
297	          label={t('Storage pool update form')}
298	        />
299	      )}
300	    </Modal>
301	  );
302	};
303	
304	export default UpdateStoragePoolModal;

